import java.util.ArrayList;
import java.util.Collections;
import java.util.HashSet;
import java.util.List;
import java.util.Random;
import java.util.Set;

import org.eclipse.rdf4j.common.transaction.IsolationLevels;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.vocabulary.FOAF;
import org.eclipse.rdf4j.model.vocabulary.RDF;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;

final class FoafCliqueDataGenerator {

	private static final String PERSON_NAMESPACE = "http://example.org/foaf/person/";
	private static final int BATCH_SIZE = 10_000;

	private final int peopleCount;
	private final int cliquePercentage;
	private final int minCliqueSize;
	private final int maxCliqueSize;
	private final int randomKnowsEdges;
	private final Random random;

	private final List<IRI> people = new ArrayList<>();
	private final Set<Long> knowsEdges = new HashSet<>();

	private int pendingStatements;

	FoafCliqueDataGenerator(int peopleCount, int cliquePercentage, int minCliqueSize, int maxCliqueSize,
			int randomKnowsEdges, long seed) {
		if (peopleCount < 1) {
			throw new IllegalArgumentException("peopleCount must be at least 1");
		}
		if (cliquePercentage < 0 || cliquePercentage > 100) {
			throw new IllegalArgumentException("cliquePercentage must be between 0 and 100");
		}
		if (minCliqueSize < 3) {
			throw new IllegalArgumentException("minCliqueSize must be at least 3");
		}
		if (maxCliqueSize < minCliqueSize) {
			throw new IllegalArgumentException("maxCliqueSize must be >= minCliqueSize");
		}
		if (randomKnowsEdges < 0) {
			throw new IllegalArgumentException("randomKnowsEdges must be >= 0");
		}
		this.peopleCount = peopleCount;
		this.cliquePercentage = cliquePercentage;
		this.minCliqueSize = minCliqueSize;
		this.maxCliqueSize = maxCliqueSize;
		this.randomKnowsEdges = randomKnowsEdges;
		this.random = new Random(seed);
	}

	void populate(SailRepositoryConnection connection) {
		ValueFactory valueFactory = connection.getValueFactory();
		knowsEdges.clear();
		pendingStatements = 0;
		connection.begin(IsolationLevels.NONE);
		try {
			createPeople(connection, valueFactory);
			createCliques(connection);
			createRandomKnowsEdges(connection);
			flush(connection);
		} catch (RuntimeException e) {
			if (connection.isActive()) {
				connection.rollback();
			}
			throw e;
		}
	}

	private void createPeople(SailRepositoryConnection connection, ValueFactory valueFactory) {
		people.clear();
		for (int i = 0; i < peopleCount; i++) {
			IRI person = valueFactory.createIRI(PERSON_NAMESPACE + i);
			people.add(person);
			addStatement(connection, person, RDF.TYPE, FOAF.PERSON);
		}
	}

	private void createCliques(SailRepositoryConnection connection) {
		List<Integer> available = new ArrayList<>(peopleCount);
		for (int i = 0; i < peopleCount; i++) {
			available.add(i);
		}
		Collections.shuffle(available, random);

		int targetCliquePeople = Math.min(peopleCount, (int) Math.round((peopleCount * cliquePercentage) / 100.0));
		int assignedPeople = 0;
		int cursor = 0;

		while (assignedPeople + minCliqueSize <= targetCliquePeople && cursor < available.size()) {
			int remainingTarget = targetCliquePeople - assignedPeople;
			int remainingAvailable = available.size() - cursor;
			int effectiveMax = Math.min(maxCliqueSize, Math.min(remainingTarget, remainingAvailable));
			if (effectiveMax < minCliqueSize) {
				break;
			}

			int cliqueSize = minCliqueSize + random.nextInt(effectiveMax - minCliqueSize + 1);
			List<Integer> members = new ArrayList<>(cliqueSize);
			for (int i = 0; i < cliqueSize; i++) {
				members.add(available.get(cursor++));
			}

			for (int source : members) {
				for (int target : members) {
					if (source != target) {
						addKnowsEdge(connection, source, target);
					}
				}
			}

			assignedPeople += cliqueSize;
		}
	}

	private void createRandomKnowsEdges(SailRepositoryConnection connection) {
		long maxEdges = (long) peopleCount * (peopleCount - 1);
		int attempts = 0;
		int added = 0;
		int maxAttempts = Math.max(randomKnowsEdges * 20, peopleCount * 10);

		while (added < randomKnowsEdges && knowsEdges.size() < maxEdges && attempts++ < maxAttempts) {
			int source = random.nextInt(peopleCount);
			int target = random.nextInt(peopleCount);
			if (source == target) {
				continue;
			}
			if (addKnowsEdge(connection, source, target)) {
				added++;
			}
		}
	}

	private boolean addKnowsEdge(SailRepositoryConnection connection, int source, int target) {
		long edgeKey = (((long) source) << 32) | (target & 0xffffffffL);
		if (!knowsEdges.add(edgeKey)) {
			return false;
		}
		addStatement(connection, people.get(source), FOAF.KNOWS, people.get(target));
		return true;
	}

	private void addStatement(SailRepositoryConnection connection, IRI subject, IRI predicate, IRI object) {
		connection.add(subject, predicate, object);
		pendingStatements++;
		if (pendingStatements >= BATCH_SIZE) {
			flush(connection);
			connection.begin(IsolationLevels.NONE);
		}
	}

	private void flush(SailRepositoryConnection connection) {
		if (connection.isActive()) {
			connection.commit();
		}
		pendingStatements = 0;
	}
}
